// build-shopify-catalog — Validate Catalog Input
// Validates store_blueprint and runtime_config; extracts shop_url and api_version.
// Safety rules: no deletes, idempotent upsert by handle, draft status for new products.

const input = $input.first().json;

const runtimeConfig  = input.runtime_config  || {};
const storeBlueprint = input.store_blueprint  || null;
const projectId      = input.project_id       || runtimeConfig.project_id || null;

if (!runtimeConfig || !runtimeConfig.project_id) {
  throw new Error('MISSING_RUNTIME_CONFIG: build-shopify-catalog requires runtime_config with project_id');
}

if (!storeBlueprint) {
  throw new Error('MISSING_ARTIFACT: store_blueprint is required but was not found in trigger input');
}

if (!Array.isArray(storeBlueprint.products) || storeBlueprint.products.length === 0) {
  throw new Error('INVALID_BLUEPRINT: store_blueprint.products must be a non-empty array');
}

// shop_url can come from runtime_config (cloud mode) or env var (self-hosted)
// In cloud mode, runtime_config is populated by resolve-runtime-config from smoke_test_config
const shopUrl    = runtimeConfig.shop_url    || runtimeConfig.STORE_OS_SHOPIFY_SHOP_URL    || null;
const apiVersion = runtimeConfig.api_version || runtimeConfig.STORE_OS_SHOPIFY_API_VERSION || '2025-01';

if (!shopUrl) {
  throw new Error(
    'MISSING_CONFIG: shop_url not found in runtime_config. ' +
    'Ensure STORE_OS_SHOPIFY_SHOP_URL is set in env or passed as smoke_test_config.STORE_OS_SHOPIFY_SHOP_URL'
  );
}

// Normalise: strip https:// if present (we add it in URL expressions)
const shopDomain = shopUrl.replace(/^https?:\/\//, '').replace(/\/$/, '');
const shopifyBase = 'https://' + shopDomain + '/admin/api/' + apiVersion;

const products    = storeBlueprint.products    || [];
const collections = storeBlueprint.collections || [];

console.log(
  `build-shopify-catalog: project=${projectId}, shop=${shopDomain}, ` +
  `products=${products.length}, collections=${collections.length}`
);

return [{
  json: {
    project_id:      projectId,
    runtime_config:  runtimeConfig,
    store_blueprint: storeBlueprint,
    shop_url:        shopUrl,
    shop_domain:     shopDomain,
    api_version:     apiVersion,
    shopify_base:    shopifyBase,
    products_count:  products.length,
    collections_count: collections.length,
  },
}];

// build-shopify-catalog — Build Upsert Plan
// Compares existing Shopify catalog against store_blueprint.
// Produces one action item per resource: {resource, action, handle, url, body, ...}
// Safety: no deletes, draft status for new products, continueOnFail on downstream HTTP nodes.

const items = $input.all();

// Pull validated config from Validate Catalog Input node (not affected by HTTP fetch overwrite)
const validated    = $node['Validate Catalog Input'].json;
const blueprint    = validated.store_blueprint;
const shopifyBase  = validated.shopify_base;
const projectId    = validated.project_id;

// Parse Merge Fetch Results — one item has custom_collections, other has products
let existingCollections = [];
let existingProducts    = [];

for (const item of items) {
  if (item.json.custom_collections !== undefined) {
    existingCollections = item.json.custom_collections || [];
  }
  if (item.json.products !== undefined) {
    existingProducts = item.json.products || [];
  }
}

// Index existing by handle for O(1) lookup
const collectionsByHandle = {};
for (const c of existingCollections) {
  if (c.handle) collectionsByHandle[c.handle] = c;
}

const productsByHandle = {};
for (const p of existingProducts) {
  if (p.handle) productsByHandle[p.handle] = p;
}

console.log(
  `Build Upsert Plan: existing collections=${existingCollections.length}, existing products=${existingProducts.length}`
);

const actions = [];

// ── Collections ───────────────────────────────────────────────────────────
for (const col of (blueprint.collections || [])) {
  const handle = col.handle || col.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');

  const collectionBody = {
    custom_collection: {
      title:      col.title,
      handle:     handle,
      body_html:  col.description || col.body_html || '',
      sort_order: col.sort_order || 'best-selling',
    },
  };

  if (collectionsByHandle[handle]) {
    // UPDATE: collection with this handle already exists
    const existingId = collectionsByHandle[handle].id;
    actions.push({
      resource:   'collection',
      action:     'update',
      handle:     handle,
      shopify_id: existingId,
      url:        shopifyBase + '/custom_collections/' + existingId + '.json',
      body:       collectionBody,
      blueprint_title: col.title,
    });
  } else {
    // CREATE: new collection
    actions.push({
      resource:   'collection',
      action:     'create',
      handle:     handle,
      shopify_id: null,
      url:        shopifyBase + '/custom_collections.json',
      body:       collectionBody,
      blueprint_title: col.title,
    });
  }
}

// ── Products ──────────────────────────────────────────────────────────────
for (const prod of (blueprint.products || [])) {
  const handle = prod.handle || prod.title.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '');

  // Derive price: use min of price_range, or fallback
  let price = '0.00';
  if (prod.price_range) {
    const raw = prod.price_range.min || prod.price_range.max || 0;
    price = parseFloat(raw).toFixed(2);
  } else if (prod.price) {
    price = parseFloat(prod.price).toFixed(2);
  }

  // Tags: array → comma-separated string (Shopify API format)
  const tags = Array.isArray(prod.tags) ? prod.tags.join(', ') : (prod.tags || '');

  const productBody = {
    product: {
      title:        prod.title,
      handle:       handle,
      body_html:    prod.description || prod.body_html || '',
      product_type: prod.product_type || '',
      tags:         tags,
      status:       'draft', // Safety: always draft — never publish automatically
      variants: [
        {
          price:              price,
          requires_shipping:  true,
          inventory_management: null, // no inventory tracking by default
        },
      ],
    },
  };

  if (productsByHandle[handle]) {
    // UPDATE: product with this handle already exists
    const existingId = productsByHandle[handle].id;
    actions.push({
      resource:   'product',
      action:     'update',
      handle:     handle,
      shopify_id: existingId,
      url:        shopifyBase + '/products/' + existingId + '.json',
      body:       productBody,
      blueprint_title: prod.title,
    });
  } else {
    // CREATE: new product
    actions.push({
      resource:   'product',
      action:     'create',
      handle:     handle,
      shopify_id: null,
      url:        shopifyBase + '/products.json',
      body:       productBody,
      blueprint_title: prod.title,
    });
  }
}

console.log(
  `Build Upsert Plan: planned actions=${actions.length} ` +
  `(creates=${actions.filter(a=>a.action==='create').length}, ` +
  `updates=${actions.filter(a=>a.action==='update').length})`
);

// If nothing to do, return a noop sentinel so downstream nodes can still execute
if (actions.length === 0) {
  return [{ json: { action: 'noop', resource: 'none', handle: null, url: null, body: null, blueprint_title: null, shopify_id: null } }];
}

return actions.map(a => ({ json: a }));

// build-shopify-catalog — Compile Deployment Summary
// Aggregates HTTP results from Create Resource and Update Resource nodes.
// Counts by statusCode (201=create success, 200=update success) and resource type.
// Returns PHASE_7B1_COMPLETE with deployment summary.

const results = $input.all();

// Pull validated config from upstream node
const validated  = $node['Validate Catalog Input'].json;
const projectId  = validated.project_id;
const shopDomain = validated.shop_domain;
const blueprint  = validated.store_blueprint;

// Tally results
let productsCreated   = 0;
let productsUpdated   = 0;
let collectionsCreated = 0;
let collectionsUpdated = 0;
const errors   = [];
const warnings = [];

for (const item of results) {
  const d = item.json;

  // Detect noop sentinel — no real operations were planned
  if (d.action === 'noop') {
    warnings.push('No catalog actions were planned — store_blueprint may be empty or all resources already match');
    continue;
  }

  // Detect HTTP error response: neverError: true means errors return as items with statusCode != 2xx
  const statusCode = d.statusCode || (d.body && d.status) || 0;
  const body       = d.body || d;

  if (statusCode >= 400 || d.error) {
    const errMsg = (body.errors ? JSON.stringify(body.errors) : null)
      || d.message
      || `HTTP ${statusCode} error`;
    errors.push({
      resource:  d._resource || 'unknown',
      handle:    d._handle   || 'unknown',
      status:    statusCode,
      message:   errMsg,
    });
    continue;
  }

  // Determine resource type from response body
  const isProduct    = !!(body.product);
  const isCollection = !!(body.custom_collection);

  if (statusCode === 201) {
    if (isProduct)    productsCreated++;
    if (isCollection) collectionsCreated++;
  } else if (statusCode === 200) {
    if (isProduct)    productsUpdated++;
    if (isCollection) collectionsUpdated++;
  } else {
    // Unexpected status — treat as warning
    warnings.push(`Unexpected HTTP ${statusCode} for ${ isProduct ? 'product' : isCollection ? 'collection' : 'resource' }`);
  }
}

const totalActioned  = productsCreated + productsUpdated + collectionsCreated + collectionsUpdated;
const totalErrors    = errors.length;
const terminalStatus = totalErrors > 0 && totalActioned === 0
  ? 'PHASE_7B1_FAILED'
  : totalErrors > 0
    ? 'PHASE_7B1_PARTIAL'
    : 'PHASE_7B1_COMPLETE';

console.log(
  `Compile Deployment Summary: status=${terminalStatus}, ` +
  `products_created=${productsCreated}, products_updated=${productsUpdated}, ` +
  `collections_created=${collectionsCreated}, collections_updated=${collectionsUpdated}, ` +
  `errors=${totalErrors}`
);

return [{
  json: {
    status:               terminalStatus,
    project_id:           projectId,
    shop_url:             shopDomain,
    completed_at:         new Date().toISOString(),

    // Deployment counts
    products_created:     productsCreated,
    products_updated:     productsUpdated,
    collections_created:  collectionsCreated,
    collections_updated:  collectionsUpdated,

    // Diagnostics
    errors:   errors,
    warnings: warnings,

    // Blueprint summary (for observability / next phase reference)
    blueprint_summary: {
      products_in_blueprint:    (blueprint.products    || []).length,
      collections_in_blueprint: (blueprint.collections || []).length,
    },

    // Safety confirmation
    safety_notes: [
      'No Shopify resources were deleted — only create and update operations were performed',
      'All new products were created with status: draft',
    ],
  },
}];
